// CAP Base Prisma Schema
// Fonte: runs/cap/001-cap-base-database/dev-base-output.md (entrega database squad CAP-BASE).
// Ajustes mínimos: relações em AuditLog, remoção de User.roles RolePermission[] (inválido),
// vínculo opcional SystemParameter ↔ SystemParameterScope.
// FASE 8 — Validação Prisma: CLI oficial do pacote em repos/cap-base/package.json (Prisma 6.19.3).
// O `npx prisma` global (v7) não valida este ficheiro sem prisma.config.ts; usar `npm run db:*` aqui.

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model Organization {
  id              Int                          @id @default(autoincrement())
  /// Corresponde ao `legalName` do domínio (campo canônico legado no schema CAP-BASE).
  name            String
  tradeName       String?
  documentNumber  String?                      @unique
  isActive        Boolean                      @default(true)
  type            OrganizationType             @relation(fields: [typeId], references: [id])
  typeId          Int
  status          OrganizationStatus           @relation(fields: [statusId], references: [id])
  statusId        Int
  roleAssignments OrganizationRoleAssignment[]
  users           UserOrganization[]
  addresses       Address[]
  contacts        Contact[]
  documents       Document[]
  createdAt       DateTime                     @default(now())
  updatedAt       DateTime                     @updatedAt
}

model OrganizationType {
  id            Int            @id @default(autoincrement())
  name          String
  organizations Organization[]
}

model OrganizationStatus {
  id            Int            @id @default(autoincrement())
  name          String
  organizations Organization[]
}

model OrganizationRole {
  id              Int                          @id @default(autoincrement())
  code            String                       @unique
  name            String
  description     String?
  isActive        Boolean                      @default(true)
  roleAssignments OrganizationRoleAssignment[]
}

model OrganizationRoleAssignment {
  id               Int              @id @default(autoincrement())
  organizationId   Int
  roleId           Int
  assignedAt       DateTime         @default(now())
  revokedAt        DateTime?
  isActive         Boolean          @default(true)
  organization     Organization     @relation(fields: [organizationId], references: [id])
  role             OrganizationRole @relation(fields: [roleId], references: [id])
}

model User {
  id                Int                @id @default(autoincrement())
  name              String
  status            UserStatus         @relation(fields: [statusId], references: [id])
  statusId          Int
  userOrganizations UserOrganization[]
  createdAt         DateTime           @default(now())
  updatedAt         DateTime           @updatedAt
}

model UserStatus {
  id    Int    @id @default(autoincrement())
  name  String
  users User[]
}

model Role {
  id          Int              @id @default(autoincrement())
  name        String
  permissions RolePermission[]
}

model Permission {
  id    Int              @id @default(autoincrement())
  name  String
  roles RolePermission[]
}

model RolePermission {
  id           Int        @id @default(autoincrement())
  roleId       Int
  permissionId Int
  role         Role       @relation(fields: [roleId], references: [id])
  permission   Permission @relation(fields: [permissionId], references: [id])
}

model UserOrganization {
  id             Int          @id @default(autoincrement())
  userId         Int
  organizationId Int
  user           User         @relation(fields: [userId], references: [id])
  organization   Organization @relation(fields: [organizationId], references: [id])
}

model Address {
  id            Int            @id @default(autoincrement())
  street        String
  number        String
  city          String
  state         String
  country       String
  type          AddressType    @relation(fields: [typeId], references: [id])
  typeId        Int
  organizations Organization[]
}

model AddressType {
  id        Int       @id @default(autoincrement())
  name      String
  addresses Address[]
}

model Contact {
  id            Int            @id @default(autoincrement())
  type          ContactType    @relation(fields: [typeId], references: [id])
  typeId        Int
  value         String
  organizations Organization[]
}

model ContactType {
  id       Int       @id @default(autoincrement())
  name     String
  contacts Contact[]
}

model Document {
  id            Int            @id @default(autoincrement())
  type          DocumentType   @relation(fields: [typeId], references: [id])
  typeId        Int
  value         String
  organizations Organization[]
}

model DocumentType {
  id        Int        @id @default(autoincrement())
  name      String
  documents Document[]
}

model SystemParameter {
  id      Int                   @id @default(autoincrement())
  key     String
  value   String
  type    SystemParameterType   @relation(fields: [typeId], references: [id])
  typeId  Int
  scope   SystemParameterScope? @relation(fields: [scopeId], references: [id])
  scopeId Int?
}

model SystemParameterType {
  id         Int               @id @default(autoincrement())
  name       String
  parameters SystemParameter[]
}

model SystemParameterScope {
  id         Int               @id @default(autoincrement())
  name       String
  parameters SystemParameter[]
}

model AuditLog {
  id           Int             @id @default(autoincrement())
  entityTypeId Int
  entityType   AuditEntityType @relation(fields: [entityTypeId], references: [id])
  entityId     Int
  actionTypeId Int
  actionType   AuditActionType @relation(fields: [actionTypeId], references: [id])
  createdAt    DateTime        @default(now())
}

model AuditActionType {
  id   Int        @id @default(autoincrement())
  name String
  logs AuditLog[]
}

model AuditEntityType {
  id   Int        @id @default(autoincrement())
  name String
  logs AuditLog[]
}
